import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Встановлення модів","description":"Покрокова інструкція по установці модів для Fabric.","frontmatter":{"title":"Встановлення модів","description":"Покрокова інструкція по установці модів для Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.10/players/installing-mods.md","filePath":"versions/1.21.10/translated/uk_ua/players/installing-mods.md","lastUpdated":1766682904000}`);var s={name:`uk_ua/1.21.10/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Встановлення модів <a class="header-anchor" href="#h1" aria-label="Permalink to “Встановлення модів”">​</a></h1><p>Ця інструкція допоможе вам встановити моди для Fabric якщо ви використовуєте запускач Minecraft.</p><p>Для запускачів сторонніх розробників слід ознайомитися з їх документацією.</p><h2 id="1-download-the-mod" tabindex="-1">1. Завантаження мода <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. Завантаження мода”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Ви повинні завантажувати моди тільки з джерел, яким ви довіряєте. Додаткову інформацію про пошук модів див. у посібнику <a href="./finding-mods">пошуку надійних модів</a>.</p></div><p>Більшість модів також потребує Fabric API, що може бути завантажено з <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> або <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>При завантаженні модів переконайтеся, що:</p><ul><li>Вони працюють з версією Minecraft, на якій ви хочете грати. Наприклад, мод що працює на версії 1.20, може не працювати на версії 1.20.2.</li><li>Вони призначені для Fabric, а не для іншого завантажувача модів.</li><li>Вони призначені для правильної версії Minecraft (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Перемістіть мод до теки <code>mods</code> <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Перемістіть мод до теки mods”">​</a></h2><p>Теку mods можна знайти в наступних місцях для кожної операційної системи.</p><p>Зазвичай ви можете вставити ці шляхи в адресний рядок провідника файлів, щоб швидко перейти до теки.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Коли ви знайдете теку <code>mods</code>, ви можете перемістити туди файли <code>.jar</code> мода.</p><p><img src="/assets/players/installing-mods.png" alt="Встановлені моди в теці mods" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. Готово! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Готово!”">​</a></h2><p>Після встановлення модів в теку <code>mods</code> ви можете відкрити запускач Minecraft і вибрати профіль Fabric зі спадного списку в нижньому лівому куті та натиснути грати!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Запускач Minecraft з вибраним профілем Fabric" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Усунення несправностей <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Усунення несправностей”">​</a></h2><p>Якщо під час виконання цієї інструкції у вас виникнуть проблеми, ви можете звернутися за допомогою в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord Fabric</a> в каналі <code>#player-support</code>.</p><p>Ви також можете спробувати розв&#39;язувати проблему самостійно, прочитавши сторінки усунення несправностей:</p><ul><li><a href="./troubleshooting/crash-reports">Звіти про збої</a></li><li><a href="./troubleshooting/uploading-logs">Завантаження журналів</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};